{
  "name": "Senior Health Insurance Benefits Advisors (SHIBA)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, seniors, and disabled citizens[1][3]",
    "asset_limits": "No asset limits; no financial eligibility requirements[1][3]",
    "other_requirements": ["Must be a Medicare beneficiary, senior, or disabled citizen seeking health insurance counseling[1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one health insurance counseling, information on Medicare Parts A/B/D, Medigap, Medicare Advantage, long-term care insurance, Medicare Savings Programs (QMB/SLMB/QI), prescription assistance, Medicaid, and other programs; printed materials and referrals; in-person, phone, or email sessions[1][2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-247-4422[2][4][5]", "Online form: https://doi.idaho.gov/shiba/[4]", "Email: Shannon.Hohl@doi.idaho.gov[2]", "In-person: Idaho Department of Insurance, 700 West State St., 3rd Floor, Boise ID 83720[2][3]"],
    "processing_time": "Not specified; appointments available upon contact[1][4]",
    "waitlist": null,
    "forms": ["Online contact form on https://doi.idaho.gov/shiba/[4]"],
    "documents": ["No specific documents required for initial counseling; bring Medicare card, insurance details, or questions for personalized advice[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide in Idaho[2][3]",
    "regional_variations": "Counselors trained and certified in every county, with local volunteers as community experts; central office in Boise but services accessible statewide via phone/email/in-person where available[3]",
    "offices_or_providers": ["Primary office: Idaho Department of Insurance, 700 West State St., 3rd Floor, Boise ID 83720; local counselors in every county[2][3]"]
  },
  "official_source": "https://doi.idaho.gov/shiba/[2][4]",
  "gotchas": ["Not an insurance seller or recommender of specific policies/agents; provides unbiased information only[3]", "Free service, no cost to users[1]", "Part of national SHIP network, focused on Medicare counseling not direct financial aid or healthcare[2][5]"],
  "data_shape_notes": "no income or asset test; free counseling service available statewide with local counselors in every county; not a benefits payment program but advisory/advocacy service[1][3]"
}

{
  "name": "Senior Community Service Employment Program (SCSEP)",
  "eligibility": {
    "age": 55,
    "income_limits": "Family income no more than 125% of the federal poverty level (HHS Poverty Guidelines, updated annually; as of January 15, 2025, contact local provider for current table by household size, e.g., for 2025: 1-person ~$19,000, 2-person ~$25,500—exact amounts vary yearly and by household size)",
    "asset_limits": null,
    "other_requirements": ["Unemployed", "U.S. citizen or authorized to work", "Priority: veterans/qualified spouses, over 65, disability, low literacy/limited English, rural resident, homeless/at risk, low employment prospects, or prior American Job Center user"]
  },
  "benefits": {
    "type": "employment",
    "value": "Paid part-time community service work training (average 20 hours/week at highest of federal/state/local minimum wage, e.g., Idaho state minimum $7.25/hour); job placement assistance, resume help, interview skills, skill training (computer, literacy, English); assignments 6-12 months at nonprofits/public agencies leading to unsubsidized jobs",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Website: www.esgw.org/scsep", "Phone: (208) 454-8555 (Easterseals-Goodwill Idaho)", "National help: 1-877-872-5627 (1-877-US2-JOBS)", "In-person: Local Easterseals-Goodwill offices in Idaho", "CareerOneStop Older Worker Program Finder for local sites"],
    "processing_time": null,
    "waitlist": "Possible due to limited slots/funding; varies by demand and region",
    "forms": [null],
    "documents": ["Proof of age (ID/driver's license)", "Proof of income (tax returns, pay stubs, benefit statements)", "Proof of unemployment", "Social Security number", "Veteran status if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Administered by Easterseals-Goodwill Northern Rocky Mountain Inc. statewide; potential waitlist/provider capacity differences by region (e.g., ties to Area Agencies on Aging in 6 planning/service areas); ICOA involvement in some planning",
    "offices_or_providers": ["Easterseals-Goodwill (primary Idaho provider)", "Contact via (208) 454-8555 or www.esgw.org/scsep for local offices"]
  },
  "official_source": "https://www.dol.gov/agencies/eta/seniors",
  "gotchas": ["Limited slots/funding may cause waitlists—call ahead", "Temporary (6-12 months) bridge to unsubsidized work, not permanent job guarantee", "Must actively seek unsubsidized employment", "Income at 125% FPL (not 100%)—many miss this threshold", "Priority tiers affect entry speed", "No asset test, but full family income counted"],
  "data_shape_notes": "income at 125% FPL (varies by household size via annual HHS guidelines); priority tiers for entry; statewide via single provider (Easterseals-Goodwill) with potential regional slot limits; no fixed asset limits"
}

{
  "name": "Idaho Legal Aid Services (Senior Legal Assistance Program)",
  "eligibility": {
    "age": 60,
    "income_limits": "At or below 125% of the federal poverty level (household income); exact dollar amounts vary by current federal poverty guidelines and household size—check current FPL tables as 2023 data used for estimates, no specific dollar table in sources[8][9]. Older references (2015) mention limits like $1,265 single/$1,705 couple for related programs but not confirmed for this[1].",
    "asset_limits": "Not specified for this program; related Medicaid eligibility referenced at $2,000 for single person (2015 data, outdated)[1].",
    "other_requirements": ["Idaho resident", "Low-income (unable to afford private legal services)", "Civil legal issues only (e.g., elder abuse, benefits access, evictions, estate planning)", "U.S. citizen or qualified resident for some benefits"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal assistance and information including stopping elder abuse/financial fraud, preventing wrongful evictions, ensuring access to Medicare/Medicaid/Social Security benefits, drafting estate-planning tools (wills, powers of attorney), community clinics on scams; provided by attorneys via hotline or direct services[3][6].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Online: Secure online application at https://idaholegalaid.org/apply-for-help (15 minutes, intake specialist contacts you)[4]", "Phone: Statewide intake line 208-746-7541 (Legal Advice Line Mon-Wed 10am-1:30pm MT / 9am-12:30pm PT, Thu closed)[4][5]", "In-person: Local ILAS offices 8:30am-4:30pm (7 offices statewide)[1][4]", "Mail: Not specified"],
    "processing_time": "Intake specialist contacts after review; no specific timeline stated[4].",
    "waitlist": "Not mentioned; may vary by case priority[4].",
    "forms": ["Secure online application (no specific name/number)", "Intake via phone or in-person"],
    "documents": ["Proof of income", "Information about legal case", "Personal identification details"][2]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Idaho residents only",
    "regional_variations": "Services via 7 local offices across Idaho; intake centralized but in-person at local offices; possible variations in wait times or case focus (e.g., East Idaho emphasizes domestic violence/housing/elder issues)[1][2].",
    "offices_or_providers": ["7 local Idaho Legal Aid Services offices statewide; contact 208-746-7541 for nearest"][1][5]
  },
  "official_source": "https://idaholegalaid.org/legal-help/seniors",
  "gotchas": ["Outdated info in guides (e.g., 2015 income/assets for related programs—verify current FPL 125%)[1]", "Civil matters only—no criminal cases[2]", "Priority for vulnerable seniors; not all cases accepted[3]", "In-person cutoff at 4:30pm; phone line limited hours/days[4]", "Income at/below 125% FPL strictly applied[9]"],
  "data_shape_notes": "Income test at 125% FPL (scales by household size via federal guidelines); statewide with 7 regional offices; senior-specific hotline for age 60+; services tiered by priority (e.g., abuse, benefits, scams)"
}

{
  "name": "Long-Term Care Ombudsman Program (Title III-B & VII)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; available to all residents regardless of income.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Must be a resident of a long-term care facility (e.g., nursing home, assisted living, skilled nursing, or residential care facility) in Idaho.", "Services provided to residents 60 years or older, or complaints made by/on behalf of such residents.", "Program authorized under Older Americans Act Titles III and VII, and Idaho Code 67-5009."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigate and resolve complaints about health, safety, welfare, and rights; advocate for residents; conduct routine facility visits (minimum quarterly); attend resident council meetings; provide information, education, referrals on long-term care and benefits; mediate issues like resident care, rehabilitation, restraints; participate in licensure surveys; maintain confidentiality.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact State Ombudsman at Idaho Commission on Aging or local Area Agency on Aging (specific numbers vary by region, e.g., South Central Idaho: 208-736-2122 or 1-800-574-8656).", "In-person: Local Ombudsman at Area Agencies on Aging or facilities.", "Online: Limited to mandated reporters/financial institutions via designated system; others call during business hours."],
    "processing_time": "Immediate response for urgent issues; investigation timelines not specified but aimed at prompt resolution.",
    "waitlist": null,
    "forms": ["No specific application form; submit complaint verbally or in writing to Ombudsman."],
    "documents": ["No documents required for families/residents to request services; provide details of complaint, resident info, and facility name."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to long-term care facilities statewide; some regions extend to home care under state statute.",
    "regional_variations": "Administered by Idaho Commission on Aging statewide with local programs via 7 Area Agencies on Aging; different regional coordinators (e.g., CSI Office on Aging covers 11 skilled nursing and 39 assisted living facilities); varying facilities served and volunteer coverage by region.",
    "offices_or_providers": ["State Ombudsman: Idaho Commission on Aging.", "Regional: Area Agencies on Aging (e.g., South Central Idaho at College of Southern Idaho)."]
  },
  "official_source": "https://aging.idaho.gov/ombudsman-program/",
  "gotchas": ["Not a direct service provider (e.g., no healthcare or financial aid); focuses on advocacy and complaint resolution only.", "Not for general eligibility determination—free service for any LTC resident with issues.", "Online reporting only for mandated reporters (e.g., physicians, nurses); families must call.", "Volunteers undergo background checks and training; families contact for resident advocacy, not to volunteer.", "Primarily facility-based; home care advocacy limited and not federally mandated."],
  "data_shape_notes": "no income test; open to all LTC residents 60+; advocacy-only (no financial benefits); regionally administered via Area Agencies on Aging with volunteer support; complaint-driven, not application-based eligibility."
}

{
  "name": "EICAP Senior Housing",
  "eligibility": {
    "age": 62,
    "income_limits": "Specific dollar amounts not detailed in sources; applicants must meet EICAP's income limits, which align with low-income thresholds for seniors in Idaho (e.g., under $1,473/month for household of 1, under $1,984/month for household of 2 per SNAP guidelines, but exact housing limits require direct inquiry).[2][3][5]",
    "asset_limits": "Not specified in sources; tenant selection criteria apply, potentially including assets similar to Medicaid HCBS ($2,000 per person).[2][3]",
    "other_requirements": ["Must meet tenant selection criteria (details available from properties).", "Persons who are 62 or older or disabled.", "Handicapped or disabled individuals may qualify at age 60 per some listings, but primary criterion is 62+ or disabled for designated senior housing."[2][5]]
  },
  "benefits": {
    "type": "in_kind",
    "value": "Affordable rental housing units in designated senior/disabled properties: Riverside Senior Housing (Idaho Falls), South Fremont Senior Housing (St. Anthony), Teton View Senior Housing (Idaho Falls). Total 92 units across Idaho Falls and St. Anthony (some sources note 300+ units including family housing).[2][5]",
    "varies_by": "region"
  },
  "application": {
    "methods": [
      "Phone: Riverside Senior Housing (208) 716-8692; Teton View Senior Housing (208) 716-8692; South Fremont Senior Housing (208) 624-7206.",
      "Contact housing units directly for applications (in-person or mail implied; no online specified).",
      "General EICAP senior services contact: Area Agency on Aging (208) 522-5391 for eligibility guidance (related services).[1][2]"
    ],
    "processing_time": "Not specified",
    "waitlist": "Likely due to limited units (92 total), but not explicitly detailed; contact properties for status.",
    "forms": ["Not specified; applications handled directly by properties."],
    "documents": ["Income verification, proof of age/disability, standard tenant application documents (prepare based on tenant selection criteria)."][2]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Eastern Idaho: Idaho Falls and St. Anthony areas.",
    "regional_variations": "Properties and phone numbers differ by location (e.g., South Fremont in St. Anthony vs. Riverside/Teton View in Idaho Falls); 92 units total in these sites.[2][5]",
    "offices_or_providers": ["Riverside Senior Housing, 450 J Street, Idaho Falls, ID 83402", "South Fremont Senior Housing, 835 West Main, St. Anthony, ID 83445", "Teton View Senior Housing, 1550 Teton View Lane, Idaho Falls, ID 83402"][2]
  },
  "official_source": "https://www.eicap.org/housing/",
  "gotchas": [
    "Not statewide—limited to specific properties in Idaho Falls and St. Anthony; families elsewhere won't qualify.",
    "Must meet both income limits AND tenant selection criteria (e.g., background checks, rental history—not just income).",
    "Age is 62+ or disabled (some references say 60+, but designated senior housing specifies 62); spouses or household details unclear.",
    "No centralized online application—call specific properties directly.",
    "Separate from EICAP's in-home senior services (age 60+); this is rental housing only.[1][2][5]"
  ],
  "data_shape_notes": "Limited to 3 physical properties in Eastern Idaho (92 units); income/tenant criteria not publicly tabulated—requires property-specific inquiry; distinguishes from broader senior services or family housing."
}
